{
  "title": "Introduction to Python for Beginners",
  "description": "A comprehensive course designed for youth in the ASEAN region to learn the fundamentals of Python programming. This course will provide a solid foundation for further exploration in various fields such as web development, data analysis, and machine learning.",
  "modules": [
    {
      "id": "module_1",
      "title": "Getting Started with Python",
      "description": "Introduction to Python programming, installation, and setting up the development environment. Learn about basic syntax, data types, and variables."
    },
    {
      "id": "module_2",
      "title": "Control Structures and Functions",
      "description": "Explore control structures such as loops and conditionals. Understand how to create and use functions to organize code effectively."
    },
    {
      "id": "module_3",
      "title": "Working with Data",
      "description": "Learn how to handle data using lists, dictionaries, and file operations. Introduction to data manipulation and storage."
    },
    {
      "id": "module_4",
      "title": "Introduction to Libraries and Applications",
      "description": "Overview of popular Python libraries and their applications in web development and data analysis. Build a simple project to apply learned concepts."
    }
  ]
}
